def integer_square_root(x):
    if x < 2:
        return x
    left, right = 1, x // 2
    ans = 1
    while left <= right:
        mid = (left + right) // 2
        sq = mid * mid
        if sq == x:
            return mid
        if sq < x:
            ans = mid
            left = mid + 1
        else:
            right = mid - 1
    return ans

